import{_ as t,o as a,c as s,a2 as n}from"./chunks/framework._O8Cueap.js";const i="/open-agent-orchestra/screenshots/external-webhook-workflow-trigger.png",b=JSON.parse('{"title":"External Integration Workflow Tutorials","description":"","frontmatter":{},"headers":[],"relativePath":"guide/external-integration-workflows.md","filePath":"guide/external-integration-workflows.md"}'),o={name:"guide/external-integration-workflows.md"};function r(l,e,d,p,h,c){return a(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="external-integration-workflow-tutorials" tabindex="-1">External Integration Workflow Tutorials <a class="header-anchor" href="#external-integration-workflow-tutorials" aria-label="Permalink to &quot;External Integration Workflow Tutorials&quot;">​</a></h1><p>External integrations in OAO follow one repeatable pattern: store secrets as credential variables, give the agent only the tools it needs, create a workflow with a clear prompt template, and expose the right trigger for the external platform.</p><p>This guide uses placeholders only. Put real credentials in OAO Variables, never in docs, prompts that will be shared, screenshots, or source control.</p><h2 id="shared-setup-pattern" tabindex="-1">Shared Setup Pattern <a class="header-anchor" href="#shared-setup-pattern" aria-label="Permalink to &quot;Shared Setup Pattern&quot;">​</a></h2><ol><li>Create credentials on the Variables page.</li><li>Create or edit an agent and enable only the integration tools it needs.</li><li>Create a workflow with a prompt template that names the expected input fields.</li><li>Add a webhook, schedule, Jira polling trigger, or system event trigger.</li><li>Test with Manual Run first when the trigger supports it.</li><li>Inspect Executions to confirm inputs, outputs, and failures are observable.</li></ol><p><img src="'+i+`" alt="External webhook workflow trigger"></p><h2 id="tutorial-1-slack-alert-notification" tabindex="-1">Tutorial 1: Slack Alert Notification <a class="header-anchor" href="#tutorial-1-slack-alert-notification" aria-label="Permalink to &quot;Tutorial 1: Slack Alert Notification&quot;">​</a></h2><p>Use this when an external system sends an alert to OAO and you want an agent to summarize it before posting to Slack.</p><h3 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;Variables&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Key</th><th>Scope</th><th>Type</th><th>Sub-type</th><th>Value</th></tr></thead><tbody><tr><td><code>SLACK_WEBHOOK_URL</code></td><td>Workspace</td><td><code>credential</code></td><td><code>secret_text</code></td><td>Slack incoming webhook URL</td></tr></tbody></table><p>Keep <strong>Inject as environment variable</strong> off unless a specific tool needs environment-variable injection. The agent can read the credential through the platform variable tools.</p><h3 id="agent" tabindex="-1">Agent <a class="header-anchor" href="#agent" aria-label="Permalink to &quot;Agent&quot;">​</a></h3><p>Create a database-backed agent named <code>Slack Alert Agent</code> with these built-in tools enabled:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td><code>read_variables</code></td><td>Resolve <code>SLACK_WEBHOOK_URL</code> at runtime</td></tr><tr><td><code>simple_http_request</code></td><td>POST the final Slack message</td></tr></tbody></table><p>Agent instructions:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Slack Alert Agent</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Summarize incoming alert payloads into concise operational messages. Include severity, source, title, and one recommended next action. Send the final message to Slack only after the summary is ready.</span></span></code></pre></div><h3 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><p>Create <code>Slack Alert Notification</code> with one step:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Read the credential variable SLACK_WEBHOOK_URL.</span></span>
<span class="line"><span>Create a concise Slack message from this alert payload.</span></span>
<span class="line"><span>Severity: {{ inputs.severity }}</span></span>
<span class="line"><span>Source: {{ inputs.source | default(&quot;unknown&quot;) }}</span></span>
<span class="line"><span>Title: {{ inputs.title | default(&quot;Untitled alert&quot;) }}</span></span>
<span class="line"><span>Description: {{ inputs.description | default(&quot;No description supplied&quot;) }}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Use simple_http_request to POST JSON to the Slack webhook URL:</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;text&quot;: &quot;[{{ inputs.severity }}] {{ inputs.title }} - recommended action: ...&quot;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Add a webhook trigger:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Type</td><td><code>Webhook</code></td></tr><tr><td>Path</td><td><code>/alerts/slack</code></td></tr><tr><td>Parameters</td><td><code>severity</code> required, <code>source</code> optional, <code>title</code> optional, <code>description</code> optional</td></tr><tr><td>Active</td><td>On after local testing succeeds</td></tr></tbody></table><h3 id="test-payload" tabindex="-1">Test Payload <a class="header-anchor" href="#test-payload" aria-label="Permalink to &quot;Test Payload&quot;">​</a></h3><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;severity&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;warning&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;source&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;weather-service&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;title&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Weekly report delayed&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;The upstream report job has not published today&#39;s summary.&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="tutorial-2-github-pull-request-review-summary" tabindex="-1">Tutorial 2: GitHub Pull Request Review Summary <a class="header-anchor" href="#tutorial-2-github-pull-request-review-summary" aria-label="Permalink to &quot;Tutorial 2: GitHub Pull Request Review Summary&quot;">​</a></h2><p>Use this when GitHub sends a pull request webhook and OAO should produce a review summary or post a comment through GitHub APIs.</p><h3 id="variables-1" tabindex="-1">Variables <a class="header-anchor" href="#variables-1" aria-label="Permalink to &quot;Variables&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Key</th><th>Scope</th><th>Type</th><th>Sub-type</th><th>Value</th></tr></thead><tbody><tr><td><code>GITHUB_TOKEN</code></td><td>Workspace or User</td><td><code>credential</code></td><td><code>GitHub Token</code></td><td>Fine-grained token with the minimum repository permissions</td></tr></tbody></table><p>Use a user-scoped token if reviews should act as the signed-in operator. Use a workspace-scoped token for shared service-account automation.</p><h3 id="agent-1" tabindex="-1">Agent <a class="header-anchor" href="#agent-1" aria-label="Permalink to &quot;Agent&quot;">​</a></h3><p>Create <code>GitHub PR Review Agent</code> with these tools:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td><code>read_variables</code></td><td>Resolve <code>GITHUB_TOKEN</code></td></tr><tr><td><code>simple_http_request</code></td><td>Call GitHub REST endpoints</td></tr></tbody></table><p>If you configure a GitHub MCP server for the agent, keep <code>simple_http_request</code> disabled unless the workflow truly needs raw HTTP access.</p><h3 id="workflow-1" tabindex="-1">Workflow <a class="header-anchor" href="#workflow-1" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><p>Prompt template:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Review the GitHub pull request payload.</span></span>
<span class="line"><span>Repository: {{ inputs.repository }}</span></span>
<span class="line"><span>Pull request: #{{ inputs.pull_request_number }}</span></span>
<span class="line"><span>Title: {{ inputs.title }}</span></span>
<span class="line"><span>Changed files summary: {{ inputs.changed_files | default(&quot;not supplied&quot;) }}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Return:</span></span>
<span class="line"><span>1. Risk summary</span></span>
<span class="line"><span>2. Suggested test focus</span></span>
<span class="line"><span>3. A short review comment body</span></span>
<span class="line"><span></span></span>
<span class="line"><span>If posting is enabled for this workflow, use GITHUB_TOKEN and simple_http_request to create a pull request comment through the GitHub REST API.</span></span></code></pre></div><p>Webhook trigger:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Type</td><td><code>Webhook</code></td></tr><tr><td>Path</td><td><code>/github/pr-review</code></td></tr><tr><td>Parameters</td><td><code>repository</code>, <code>pull_request_number</code>, <code>title</code>, <code>changed_files</code></td></tr></tbody></table><h2 id="tutorial-3-http-enrichment-before-ticket-routing" tabindex="-1">Tutorial 3: HTTP Enrichment Before Ticket Routing <a class="header-anchor" href="#tutorial-3-http-enrichment-before-ticket-routing" aria-label="Permalink to &quot;Tutorial 3: HTTP Enrichment Before Ticket Routing&quot;">​</a></h2><p>Use this when a workflow must enrich an incoming request with data from a CRM, inventory system, or internal API before deciding how to route it.</p><h3 id="variables-2" tabindex="-1">Variables <a class="header-anchor" href="#variables-2" aria-label="Permalink to &quot;Variables&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Key</th><th>Scope</th><th>Type</th><th>Sub-type</th><th>Value</th></tr></thead><tbody><tr><td><code>CUSTOMER_API_BASE_URL</code></td><td>Workspace</td><td><code>property</code></td><td>n/a</td><td><code>https://api.example.internal</code></td></tr><tr><td><code>CUSTOMER_API_TOKEN</code></td><td>Workspace</td><td><code>credential</code></td><td><code>secret_text</code></td><td>API bearer token</td></tr></tbody></table><h3 id="agent-2" tabindex="-1">Agent <a class="header-anchor" href="#agent-2" aria-label="Permalink to &quot;Agent&quot;">​</a></h3><p>Create <code>Customer Enrichment Agent</code> with <code>read_variables</code> and <code>simple_http_request</code> enabled.</p><h3 id="workflow-2" tabindex="-1">Workflow <a class="header-anchor" href="#workflow-2" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><p>Step 1, <code>Fetch Customer Context</code>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Read CUSTOMER_API_BASE_URL and CUSTOMER_API_TOKEN.</span></span>
<span class="line"><span>Use simple_http_request to GET:</span></span>
<span class="line"><span>{{ properties.CUSTOMER_API_BASE_URL }}/customers/{{ inputs.customer_id }}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Return the customer tier, region, open incidents, and renewal date.</span></span></code></pre></div><p>Step 2, <code>Route Ticket</code>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Using the enrichment result below, decide the support queue and priority.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Customer context:</span></span>
<span class="line"><span>{{ precedent_output }}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ticket:</span></span>
<span class="line"><span>{{ inputs.description }}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Return JSON with queue, priority, reason, and recommended owner.</span></span></code></pre></div><p>Webhook trigger:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Type</td><td><code>Webhook</code></td></tr><tr><td>Path</td><td><code>/support/enrich</code></td></tr><tr><td>Parameters</td><td><code>customer_id</code> required, <code>description</code> required</td></tr></tbody></table><h2 id="tutorial-4-jira-weather-report-request" tabindex="-1">Tutorial 4: Jira Weather Report Request <a class="header-anchor" href="#tutorial-4-jira-weather-report-request" aria-label="Permalink to &quot;Tutorial 4: Jira Weather Report Request&quot;">​</a></h2><p>For Jira polling or Jira dynamic webhook setup, use the dedicated <a href="/open-agent-orchestra/guide/jira-integration.html">Jira Integration Tutorial</a>. The short version is:</p><ol><li>Store <code>JIRA_API_TOKEN</code> as a workspace credential.</li><li>Create an agent that can process Jira issue payloads.</li><li>Create a workflow prompt that reads <code>inputs.jiraIssues</code> and <code>inputs.jiraIssueKeys</code>.</li><li>Add a Jira polling trigger with JQL such as:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>project = OAO AND description ~ &quot;Get a Weekly Weather Report&quot; ORDER BY updated DESC</span></span></code></pre></div><p>The live Playwright E2E creates a real Jira issue with description <code>Get a Weekly Weather Report</code>, waits for OAO to record a workflow execution, and deletes the temporary issue.</p><h2 id="verification-checklist" tabindex="-1">Verification Checklist <a class="header-anchor" href="#verification-checklist" aria-label="Permalink to &quot;Verification Checklist&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Variable list</td><td>Credential rows show metadata only, never raw values</td></tr><tr><td>Agent edit page</td><td>Model and integration credentials appear as selectable variable references</td></tr><tr><td>Workflow trigger card</td><td>Webhook path, Jira JQL, or polling interval is visible without exposing secrets</td></tr><tr><td>Execution detail</td><td>Inputs, status, agent step output, and failures are auditable</td></tr><tr><td>Cleanup</td><td>Deleting a workflow removes its triggers and does not leave stale automation endpoints</td></tr></tbody></table>`,57)])])}const k=t(o,[["render",r]]);export{b as __pageData,k as default};
